Create the `DeadLetterDetailSheet` component that displays dead letter group details when a user clicks "View" on a dead letter attention item.

## Implementation

Create `apps/client/src/layers/features/dashboard-attention/ui/DeadLetterDetailSheet.tsx`:

```typescript
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  Badge,
  Button,
  ScrollArea,
} from '@/layers/shared/ui';
import { useAggregatedDeadLetters, useDismissDeadLetterGroup } from '@/layers/entities/relay';
import { formatRelativeTime } from '../lib/format-relative-time';

interface DeadLetterDetailSheetProps {
  open: boolean;
  itemId: string | undefined;
  onClose: () => void;
}

/**
 * Detail sheet for a dead letter group, showing message count, reason,
 * timestamps, sample payload, and a dismiss action.
 */
export function DeadLetterDetailSheet({ open, itemId, onClose }: DeadLetterDetailSheetProps) {
  const { data: deadLetters } = useAggregatedDeadLetters();
  const dismissMutation = useDismissDeadLetterGroup();

  // Parse compound key: "source::reason"
  const [source, reason] = itemId?.split('::') ?? [undefined, undefined];

  // Find matching group from cached data
  const group = deadLetters?.find((g) => g.source === source && g.reason === reason);

  const handleDismiss = () => {
    if (!source || !reason) return;
    dismissMutation.mutate(
      { source, reason },
      { onSuccess: onClose }
    );
  };

  return (
    <Sheet open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <SheetContent side="right">
        <SheetHeader>
          <SheetTitle>Dead Letters</SheetTitle>
          <SheetDescription>{source ?? 'Unknown source'}</SheetDescription>
        </SheetHeader>

        <ScrollArea className="flex-1 px-4">
          {group ? (
            <div className="space-y-4">
              {/* Summary */}
              <div className="space-y-2">
                <p className="text-foreground text-sm">
                  {group.count} undeliverable message{group.count === 1 ? '' : 's'}
                </p>
                <Badge variant="secondary">{group.reason}</Badge>
              </div>

              {/* Timestamps */}
              <div className="space-y-1 text-sm">
                <p className="text-muted-foreground">
                  First seen: {formatRelativeTime(group.firstSeen)} ago
                </p>
                <p className="text-muted-foreground">
                  Last seen: {formatRelativeTime(group.lastSeen)} ago
                </p>
              </div>

              {/* Sample payload */}
              {group.sample && (
                <div className="space-y-1">
                  <p className="text-muted-foreground text-xs font-medium">Sample payload</p>
                  <pre className="bg-muted rounded-md p-3 text-xs font-mono overflow-x-auto">
                    {JSON.stringify(group.sample, null, 2)}
                  </pre>
                </div>
              )}
            </div>
          ) : (
            <p className="text-muted-foreground py-8 text-center text-sm">
              This item has been resolved.
            </p>
          )}
        </ScrollArea>

        <SheetFooter>
          {group && (
            <Button
              variant="destructive"
              onClick={handleDismiss}
              disabled={dismissMutation.isPending}
            >
              {dismissMutation.isPending ? 'Dismissing...' : 'Dismiss Group'}
            </Button>
          )}
          <Button variant="outline" onClick={onClose}>
            Close
          </Button>
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}
```

## Key Decisions

- Uses `useAggregatedDeadLetters()` which is already cached/polling — no new API call
- The `itemId` is a compound key `source::reason` split on `::` delimiter
- When the group is not found (resolved between render and open), shows "This item has been resolved" empty state
- Dismiss action calls `useDismissDeadLetterGroup()` mutation and closes the Sheet on success
- The `sample` field on `AggregatedDeadLetter` is optional — only rendered if present
- Sheet uses `onOpenChange` to handle close via overlay click, Escape key, and X button

## Files Created

- `apps/client/src/layers/features/dashboard-attention/ui/DeadLetterDetailSheet.tsx`

## Acceptance Criteria

- Sheet renders dead letter details (source, reason badge, count, timestamps) when `open=true` and matching data exists
- Shows sample payload as formatted JSON when `sample` field is present
- Shows "This item has been resolved" when no matching group is found
- Does not render content when `open=false`
- Dismiss button calls `useDismissDeadLetterGroup` with correct `source` and `reason`
- Sheet closes on successful dismiss
- Dismiss button shows loading state while mutation is pending
- `pnpm typecheck` passes

Create the `FailedRunDetailSheet` component that displays failed Pulse run details when a user clicks "View" on a failed run attention item.

## Implementation

Create `apps/client/src/layers/features/dashboard-attention/ui/FailedRunDetailSheet.tsx`:

```typescript
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  Badge,
  Button,
  ScrollArea,
  Skeleton,
} from '@/layers/shared/ui';
import { useRun, useCancelRun } from '@/layers/entities/pulse';
import { useNavigate } from '@tanstack/react-router';
import { formatRelativeTime } from '../lib/format-relative-time';

interface FailedRunDetailSheetProps {
  open: boolean;
  itemId: string | undefined;
  onClose: () => void;
}

/** Format milliseconds to a human-readable duration (e.g. "2m 30s"). */
function formatDuration(ms: number): string {
  const seconds = Math.floor(ms / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  const remainingSeconds = seconds % 60;
  if (minutes < 60) return `${minutes}m ${remainingSeconds}s`;
  const hours = Math.floor(minutes / 60);
  const remainingMinutes = minutes % 60;
  return `${hours}h ${remainingMinutes}m`;
}

/**
 * Detail sheet for a failed Pulse run, showing status, trigger, timeline,
 * error message, output summary, and available actions.
 */
export function FailedRunDetailSheet({ open, itemId, onClose }: FailedRunDetailSheetProps) {
  const { data: run, isLoading, isError } = useRun(open ? (itemId ?? null) : null);
  const cancelMutation = useCancelRun();
  const navigate = useNavigate();

  const handleViewSession = () => {
    if (!run?.sessionId) return;
    void navigate({
      to: '/session',
      search: { session: run.sessionId },
    });
  };

  const handleCancel = () => {
    if (!run) return;
    cancelMutation.mutate(run.id);
  };

  return (
    <Sheet open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <SheetContent side="right">
        <SheetHeader>
          <SheetTitle>Failed Run</SheetTitle>
          <SheetDescription>
            {itemId ? itemId.slice(0, 8) : 'Unknown'}
          </SheetDescription>
        </SheetHeader>

        <ScrollArea className="flex-1 px-4">
          {isLoading && (
            <div className="space-y-4">
              <Skeleton className="h-6 w-24" />
              <Skeleton className="h-4 w-48" />
              <Skeleton className="h-20 w-full" />
            </div>
          )}

          {isError && (
            <p className="text-destructive py-8 text-center text-sm">
              Failed to load run details.
            </p>
          )}

          {!isLoading && !isError && !run && (
            <p className="text-muted-foreground py-8 text-center text-sm">
              This item has been resolved.
            </p>
          )}

          {run && (
            <div className="space-y-4">
              {/* Status and trigger badges */}
              <div className="flex gap-2">
                <Badge variant="destructive">Failed</Badge>
                <Badge variant="secondary">
                  {run.trigger === 'scheduled' ? 'Scheduled' : 'Manual'}
                </Badge>
              </div>

              {/* Timeline */}
              <div className="space-y-1 text-sm">
                {run.startedAt && (
                  <p className="text-muted-foreground">
                    Started: {formatRelativeTime(run.startedAt)} ago
                  </p>
                )}
                {run.finishedAt && (
                  <p className="text-muted-foreground">
                    Finished: {formatRelativeTime(run.finishedAt)} ago
                  </p>
                )}
                {run.durationMs != null && (
                  <p className="text-muted-foreground">
                    Duration: {formatDuration(run.durationMs)}
                  </p>
                )}
              </div>

              {/* Error message */}
              {run.error && (
                <div className="bg-destructive/10 border-destructive/20 rounded-md border p-3">
                  <p className="text-destructive text-sm font-medium">Error</p>
                  <p className="text-destructive/80 mt-1 text-sm">{run.error}</p>
                </div>
              )}

              {/* Output summary */}
              {run.outputSummary && (
                <div className="space-y-1">
                  <p className="text-muted-foreground text-xs font-medium">Output</p>
                  <pre className="bg-muted max-h-48 overflow-auto rounded-md p-3 text-xs font-mono">
                    {run.outputSummary}
                  </pre>
                </div>
              )}
            </div>
          )}
        </ScrollArea>

        <SheetFooter>
          {run?.sessionId && (
            <Button variant="default" onClick={handleViewSession}>
              View Session
            </Button>
          )}
          {run?.status === 'running' && (
            <Button
              variant="destructive"
              onClick={handleCancel}
              disabled={cancelMutation.isPending}
            >
              {cancelMutation.isPending ? 'Cancelling...' : 'Cancel'}
            </Button>
          )}
          <Button variant="outline" onClick={onClose}>
            Close
          </Button>
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}
```

## Key Decisions

- Uses `useRun(itemId)` which fetches a single run by ID — this is the only potentially new API call, triggered on demand when Sheet opens
- The query is only enabled when `open` is true (prevents unnecessary fetches when Sheet is closed)
- Loading state renders Skeleton shimmer components
- Error state shows an inline error message
- Resolved state (run not found) shows "This item has been resolved"
- "View Session" button only appears when `sessionId` is present
- "Cancel" button only appears when run status is `'running'` (edge case for runs that failed after attention item was created)
- `formatDuration` is a local helper converting milliseconds to human-readable format

## Files Created

- `apps/client/src/layers/features/dashboard-attention/ui/FailedRunDetailSheet.tsx`

## Acceptance Criteria

- Sheet renders run details (status badge, trigger badge, timeline, error, output) when data loads
- Shows loading skeleton while `useRun()` is fetching
- Shows error state when fetch fails
- Shows "This item has been resolved" when run not found
- Shows "View Session" link only when `sessionId` exists — clicking navigates to `/session?session=<sessionId>`
- Shows "Cancel" button only when `status === 'running'`
- Does not fetch data when `open=false`
- `pnpm typecheck` passes

Create the `OfflineAgentDetailSheet` component that displays a list of offline/unreachable mesh agents when a user clicks "View" on the offline agent attention item.

## Implementation

Create `apps/client/src/layers/features/dashboard-attention/ui/OfflineAgentDetailSheet.tsx`:

```typescript
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  Badge,
  Button,
  ScrollArea,
} from '@/layers/shared/ui';
import { useRegisteredAgents } from '@/layers/entities/mesh';
import { useAgentVisual } from '@/layers/entities/agent';
import { formatRelativeTime } from '../lib/format-relative-time';
import { Check } from 'lucide-react';
import type { MeshAgent } from '@dorkos/shared/types';

interface OfflineAgentDetailSheetProps {
  open: boolean;
  onClose: () => void;
}

interface AgentRowProps {
  agent: MeshAgent;
}

/** Single offline agent row with visual identity, status, and last seen time. */
function AgentRow({ agent }: AgentRowProps) {
  const visual = useAgentVisual(agent.manifest ?? null, agent.cwd ?? '');

  return (
    <div className="flex items-center gap-3 py-2">
      <span className="text-lg" aria-hidden>
        {visual.emoji}
      </span>
      <div
        className="size-2 shrink-0 rounded-full"
        style={{ backgroundColor: visual.color }}
      />
      <div className="min-w-0 flex-1">
        <p className="text-foreground truncate text-sm font-medium">
          {agent.name}
        </p>
        <div className="flex items-center gap-2">
          <Badge variant="destructive" className="text-xs">
            Unreachable
          </Badge>
          {agent.runtime && (
            <Badge variant="secondary" className="text-xs">
              {agent.runtime}
            </Badge>
          )}
        </div>
      </div>
      {agent.lastSeenAt && (
        <span className="text-muted-foreground shrink-0 text-xs">
          {formatRelativeTime(agent.lastSeenAt)} ago
        </span>
      )}
    </div>
  );
}

/**
 * Detail sheet listing all offline/unreachable mesh agents with their
 * visual identity, status badges, runtime info, and last-seen timestamps.
 */
export function OfflineAgentDetailSheet({ open, onClose }: OfflineAgentDetailSheetProps) {
  const { data: agents } = useRegisteredAgents();

  // Filter to only unreachable agents
  const offlineAgents = agents?.filter((a) => a.status === 'unreachable') ?? [];

  return (
    <Sheet open={open} onOpenChange={(isOpen) => !isOpen && onClose()}>
      <SheetContent side="right">
        <SheetHeader>
          <SheetTitle>Offline Agents</SheetTitle>
          <SheetDescription>
            {offlineAgents.length} agent{offlineAgents.length === 1 ? '' : 's'} unreachable
          </SheetDescription>
        </SheetHeader>

        <ScrollArea className="flex-1 px-4">
          {offlineAgents.length > 0 ? (
            <div className="divide-y">
              {offlineAgents.map((agent) => (
                <AgentRow key={agent.id} agent={agent} />
              ))}
            </div>
          ) : (
            <div className="flex flex-col items-center gap-2 py-8">
              <Check className="text-green-500 size-6" />
              <p className="text-muted-foreground text-sm">All agents are online</p>
            </div>
          )}
        </ScrollArea>

        <SheetFooter>
          <Button variant="outline" onClick={onClose}>
            Close
          </Button>
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}
```

## Key Decisions

- Uses `useRegisteredAgents()` (already cached) filtered client-side to `status === 'unreachable'`
- Does NOT accept `itemId` prop — the offline agent attention item uses sentinel value `'offline'` and shows all unreachable agents as a group
- Uses `useAgentVisual()` from `entities/agent` for consistent emoji + color identity per agent
- `AgentRow` is extracted as a local sub-component for readability
- Empty state (all agents came back online before Sheet opened) shows green checkmark with "All agents are online"
- The `agent.manifest` may be null for agents that haven't published a manifest — `useAgentVisual` handles this by falling back to CWD-based hash
- Agent type `MeshAgent` should be imported from `@dorkos/shared/types` — verify the exact type name during implementation and adjust if needed (may be `RegisteredAgent` or similar)

## FSD Layer Compliance

- `features/dashboard-attention` importing from `entities/mesh` and `entities/agent` — allowed
- `features/dashboard-attention` importing from `shared/ui` — allowed

